async (params, browser) => {
  // Open story page
  await browser.open(`${params.story_url}`)

  // Wait for story to load
  await browser.waitForSelector('.athing, .fatitem', 15000)

  // Let comments load
  await browser.wait(2000)

  // Extract story and comments
  const story_data = await browser.evaluate(`const titleEl = document.querySelector('.titleline > a'); const subtext = document.querySelector('.subtext'); const scoreEl = subtext ? subtext.querySelector('.score') : null; const authorEl = subtext ? subtext.querySelector('.hnuser') : null; const ageEl = subtext ? subtext.querySelector('.age a') : null; let storyCommentCount = '0'; if (subtext) { const links = subtext.querySelectorAll('a'); for (const link of links) { const text = link.textContent.trim(); if (text.includes('comment')) { storyCommentCount = text.split('\u00a0')[0] || text.split(' ')[0]; break; } } } const comments = []; const commentRows = document.querySelectorAll('.comtr'); for (let i = 0; i < Math.min(commentRows.length, 30); i++) { const c = commentRows[i]; const indentTd = c.querySelector('td.ind'); const depth = indentTd && indentTd.getAttribute('indent') ? parseInt(indentTd.getAttribute('indent'), 10) : 0; const cAuthor = c.querySelector('.hnuser'); const cText = c.querySelector('.commtext'); const cAge = c.querySelector('.age a'); comments.push({ author: cAuthor ? cAuthor.textContent.trim() : '[deleted]', content: cText ? cText.textContent.trim().slice(0, 800) : '[deleted]', time: cAge ? cAge.textContent.trim() : '', depth: depth }); } return { title: titleEl ? titleEl.textContent.trim() : '', url: titleEl ? titleEl.href : '', score: scoreEl ? scoreEl.textContent.trim() : '0 points', author: authorEl ? authorEl.textContent.trim() : '', time: ageEl ? ageEl.textContent.trim() : '', total_comments: storyCommentCount, comments_scraped: comments.length, comments: comments, story_url: window.location.href }`)

  return story_data
}
